"""Phase 1 Capstone: AI Work Assistant — full integration of all Phase 1 skills."""
import os
import json
import time
from abc import ABC, abstractmethod
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Literal
from pydantic import BaseModel, Field
from openai import OpenAI

oai = OpenAI(api_key=os.environ["OPENAI_API_KEY"])


# ── Pydantic schema for /extract ─────────────────────────────────
class ExtractedData(BaseModel):
    entities: list[str] = Field(default_factory=list)
    key_facts: list[str] = Field(default_factory=list)
    dates: list[str] = Field(default_factory=list)
    numbers: list[str] = Field(default_factory=list)
    sentiment: Literal["positive", "negative", "neutral", "mixed"] = "neutral"


# ── Usage tracking ────────────────────────────────────────────────
@dataclass
class CommandUsage:
    calls: int = 0
    input_tokens: int = 0
    output_tokens: int = 0

    def cost(self) -> float:
        return (self.input_tokens / 1e6) * 0.15 + (self.output_tokens / 1e6) * 0.60  # mini pricing


@dataclass
class UsageDashboard:
    by_command: dict = field(default_factory=lambda: defaultdict(CommandUsage))

    def record(self, command: str, in_t: int, out_t: int) -> None:
        u = self.by_command[command]
        u.calls += 1
        u.input_tokens += in_t
        u.output_tokens += out_t

    def total_cost(self) -> float:
        return sum(u.cost() for u in self.by_command.values())

    def display(self) -> str:
        lines = ["\n╔══════════════════════════════════════╗",
                 "║         SESSION STATISTICS           ║",
                 "╠══════════════════════════════════════╣"]
        total_calls = sum(u.calls for u in self.by_command.values())
        total_in  = sum(u.input_tokens for u in self.by_command.values())
        total_out = sum(u.output_tokens for u in self.by_command.values())
        lines += [
            f"║ Total calls:    {total_calls:<20}║",
            f"║ Input tokens:   {total_in:<20,}║",
            f"║ Output tokens:  {total_out:<20,}║",
            f"║ Est. cost:      ${self.total_cost():<19.5f}║",
            "╠══════════════════════════════════════╣",
            "║ By command:                          ║",
        ]
        for cmd, u in sorted(self.by_command.items()):
            line = f"  {cmd:<12} {u.calls} calls  ${u.cost():.5f}"
            lines.append(f"║ {line:<36}║")
        lines.append("╚══════════════════════════════════════╝")
        return "\n".join(lines)


# ── Command handlers ─────────────────────────────────────────────
class BaseHandler(ABC):
    SYSTEM = ""
    PARAMS: dict = {}

    @abstractmethod
    def handle(self, user_input: str) -> tuple[str, int, int]: ...


class ChatHandler(BaseHandler):
    SYSTEM = "You are a helpful AI work assistant. Be concise and practical."
    PARAMS = {"temperature": 0.7, "max_tokens": 800}

    def __init__(self):
        self.history: list[dict] = []

    def handle(self, user_input: str) -> tuple[str, int, int]:
        self.history.append({"role": "user", "content": user_input})
        # Prune to last 20 messages
        if len(self.history) > 20:
            self.history = self.history[-20:]
        messages = [{"role": "system", "content": self.SYSTEM}] + self.history
        r = oai.chat.completions.create(model="gpt-4o-mini", messages=messages, **self.PARAMS)
        reply = r.choices[0].message.content
        self.history.append({"role": "assistant", "content": reply})
        return reply, r.usage.prompt_tokens, r.usage.completion_tokens


class SummarizeHandler(BaseHandler):
    SYSTEM = """You are a professional document summarizer.
Produce concise, accurate summaries under 200 words.
Use bullet points for key facts. Preserve all numbers and dates.
Never add information not present in the original."""
    PARAMS = {"temperature": 0.3, "max_tokens": 400}

    def handle(self, user_input: str) -> tuple[str, int, int]:
        messages = [{"role": "system", "content": self.SYSTEM},
                    {"role": "user",   "content": f"Summarize:\n\n<document>\n{user_input}\n</document>"}]
        r = oai.chat.completions.create(model="gpt-4o-mini", messages=messages, **self.PARAMS)
        return r.choices[0].message.content, r.usage.prompt_tokens, r.usage.completion_tokens


class ExtractHandler(BaseHandler):
    def handle(self, user_input: str) -> tuple[str, int, int]:
        completion = oai.beta.chat.completions.parse(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": "Extract structured information from the text."},
                {"role": "user",   "content": user_input}
            ],
            response_format=ExtractedData,
            temperature=0.0,
        )
        data = completion.choices[0].message.parsed
        usage = completion.usage
        output = json.dumps(data.model_dump(), indent=2)
        return output, usage.prompt_tokens, usage.completion_tokens


class ReviewHandler(BaseHandler):
    SYSTEM = """You are a senior software engineer performing code review.
Use chain-of-thought:
1. UNDERSTAND: What does this code do?
2. ANALYZE: Check for bugs, edge cases, security issues, performance
3. VERDICT: Overall quality and top 3 improvements"""
    PARAMS = {"temperature": 0.1, "max_tokens": 1000}

    def handle(self, user_input: str) -> tuple[str, int, int]:
        messages = [{"role": "system", "content": self.SYSTEM},
                    {"role": "user",   "content": f"Review this code:\n```\n{user_input}\n```"}]
        r = oai.chat.completions.create(model="gpt-4o-mini", messages=messages, **self.PARAMS)
        return r.choices[0].message.content, r.usage.prompt_tokens, r.usage.completion_tokens


class ResearchHandler(BaseHandler):
    SYSTEM = """You are a research analyst. Answer questions in three phases:
1. ANALYZE: What information is needed?
2. REASON: Work through step by step
3. CONCLUDE: Clear, actionable answer"""
    PARAMS = {"temperature": 0.2, "max_tokens": 1500}

    def handle(self, user_input: str) -> tuple[str, int, int]:
        messages = [{"role": "system", "content": self.SYSTEM},
                    {"role": "user",   "content": user_input}]
        r = oai.chat.completions.create(model="gpt-4o-mini", messages=messages, **self.PARAMS)
        return r.choices[0].message.content, r.usage.prompt_tokens, r.usage.completion_tokens


# ── Main assistant ────────────────────────────────────────────────
class AIAssistant:
    HANDLERS = {
        "/chat":      ChatHandler,
        "/summarize": SummarizeHandler,
        "/extract":   ExtractHandler,
        "/review":    ReviewHandler,
        "/research":  ResearchHandler,
    }

    def __init__(self):
        self.dashboard = UsageDashboard()
        self.handlers  = {cmd: cls() for cmd, cls in self.HANDLERS.items()}
        self.active_cmd = "/chat"

    def process(self, user_input: str) -> str:
        stripped = user_input.strip()

        if stripped == "/cost":
            return self.dashboard.display()
        if stripped == "/help":
            return "Commands: " + ", ".join(list(self.HANDLERS.keys()) + ["/cost", "/help", "/quit"])
        if stripped in self.HANDLERS:
            self.active_cmd = stripped
            return f"Switched to {stripped} mode."

        handler = self.handlers[self.active_cmd]
        try:
            reply, in_t, out_t = handler.handle(stripped)
            self.dashboard.record(self.active_cmd, in_t, out_t)
            return reply
        except Exception as e:
            return f"Error: {e}"

    def run(self) -> None:
        print("AI Work Assistant | Type /help for commands | /quit to exit")
        print(f"Mode: {self.active_cmd}")
        while True:
            try:
                user_input = input("\nYou: ").strip()
                if not user_input:
                    continue
                if user_input == "/quit":
                    print(self.dashboard.display())
                    break
                print(f"\nAssistant [{self.active_cmd}]:")
                print(self.process(user_input))
            except KeyboardInterrupt:
                print("\n" + self.dashboard.display())
                break


if __name__ == "__main__":
    assistant = AIAssistant()
    assistant.run()
